"""Expression calculator with variable support."""


class Calculator:
    """Evaluate arithmetic expressions with variables.

    Supported features:
    - Arithmetic: +, -, *, /  (correct operator precedence)
    - Parentheses for grouping
    - Unary minus (negative numbers)
    - Decimal numbers
    - Variable assignment  (x = 5)  and usage
    - Errors: ZeroDivisionError, NameError, SyntaxError
    """

    def __init__(self):
        self._vars: dict[str, float] = {}

    # ------------------------------------------------------------------
    # Public interface
    # ------------------------------------------------------------------

    def eval(self, expression: str) -> float:
        """Parse and evaluate *expression*, returning its numeric value."""
        self._src = expression.strip()
        self._pos = 0
        result = self._parse_expression()
        self._skip_whitespace()
        if self._pos < len(self._src):
            raise SyntaxError(
                f"Unexpected character '{self._src[self._pos]}' "
                f"at position {self._pos}"
            )
        return result

    # ------------------------------------------------------------------
    # Tokeniser helpers
    # ------------------------------------------------------------------

    def _skip_whitespace(self):
        while self._pos < len(self._src) and self._src[self._pos].isspace():
            self._pos += 1

    def _peek(self) -> str:
        """Return the current character without consuming it ('' at EOF)."""
        self._skip_whitespace()
        if self._pos < len(self._src):
            return self._src[self._pos]
        return ""

    def _consume(self, ch: str):
        """Consume an expected character or raise SyntaxError."""
        self._skip_whitespace()
        if self._pos >= len(self._src) or self._src[self._pos] != ch:
            got = (
                f"'{self._src[self._pos]}'"
                if self._pos < len(self._src)
                else "end of expression"
            )
            raise SyntaxError(f"Expected '{ch}', got {got}")
        self._pos += 1

    # ------------------------------------------------------------------
    # Grammar
    #
    #   expression   вЖТ assignment | additive
    #   assignment   вЖТ IDENT '=' expression
    #   additive     вЖТ multiplicative ( ('+' | '-') multiplicative )*
    #   multiplicative вЖТ unary ( ('*' | '/') unary )*
    #   unary        вЖТ '-' unary | primary
    #   primary      вЖТ NUMBER | IDENT | '(' expression ')'
    # ------------------------------------------------------------------

    def _parse_expression(self) -> float:
        """Top-level: handle assignment or fall through to additive."""
        # Speculatively check for  IDENT  '='  (but NOT '==')
        saved_pos = self._pos
        self._skip_whitespace()
        name = self._try_read_identifier()
        if name is not None:
            self._skip_whitespace()
            if (
                self._pos < len(self._src)
                and self._src[self._pos] == "="
                and (
                    self._pos + 1 >= len(self._src)
                    or self._src[self._pos + 1] != "="
                )
            ):
                self._pos += 1  # consume '='
                value = self._parse_expression()
                self._vars[name] = value
                return value
        # Not an assignment вАУ backtrack
        self._pos = saved_pos
        return self._parse_additive()

    def _try_read_identifier(self) -> "str | None":
        """Read an identifier starting at current pos; return None if none."""
        self._skip_whitespace()
        if self._pos >= len(self._src) or not (
            self._src[self._pos].isalpha() or self._src[self._pos] == "_"
        ):
            return None
        start = self._pos
        while self._pos < len(self._src) and (
            self._src[self._pos].isalnum() or self._src[self._pos] == "_"
        ):
            self._pos += 1
        return self._src[start : self._pos]

    def _parse_additive(self) -> float:
        left = self._parse_multiplicative()
        while True:
            op = self._peek()
            if op == "+":
                self._pos += 1
                left += self._parse_multiplicative()
            elif op == "-":
                self._pos += 1
                left -= self._parse_multiplicative()
            else:
                break
        return left

    def _parse_multiplicative(self) -> float:
        left = self._parse_unary()
        while True:
            op = self._peek()
            if op == "*":
                self._pos += 1
                left *= self._parse_unary()
            elif op == "/":
                self._pos += 1
                right = self._parse_unary()
                if right == 0:
                    raise ZeroDivisionError("Division by zero")
                left /= right
            else:
                break
        return left

    def _parse_unary(self) -> float:
        op = self._peek()
        if op == "-":
            self._pos += 1
            return -self._parse_unary()
        if op == "+":
            self._pos += 1
            return self._parse_unary()
        return self._parse_primary()

    def _parse_primary(self) -> float:
        ch = self._peek()

        # Grouped expression
        if ch == "(":
            self._pos += 1
            value = self._parse_expression()
            self._consume(")")
            return value

        # Number literal (integer or decimal)
        if ch.isdigit() or ch == ".":
            return self._read_number()

        # Identifier (variable reference)
        if ch.isalpha() or ch == "_":
            name = self._try_read_identifier()
            if name not in self._vars:
                raise NameError(f"Undefined variable: '{name}'")
            return self._vars[name]

        if ch == "":
            raise SyntaxError("Unexpected end of expression")
        raise SyntaxError(f"Unexpected character '{ch}' at position {self._pos}")

    def _read_number(self) -> float:
        start = self._pos
        has_dot = False
        while self._pos < len(self._src):
            c = self._src[self._pos]
            if c.isdigit():
                self._pos += 1
            elif c == "." and not has_dot:
                has_dot = True
                self._pos += 1
            else:
                break
        token = self._src[start : self._pos]
        if not token or token == ".":
            raise SyntaxError(f"Invalid number literal near position {start}")
        return float(token)

"""Expression calculator with variable support."""


class Calculator:
    """Evaluate arithmetic expressions with variables.

    Supported features:
    - Operators  : +  -  *  /  (with standard precedence)
    - Parentheses: (expr)
    - Unary minus: -expr
    - Decimals   : 3.14
    - Variables  : name = expr  /  name in expressions
    """

    def __init__(self):
        self._vars: dict[str, float] = {}

    # ------------------------------------------------------------------ #
    #  Public interface                                                    #
    # ------------------------------------------------------------------ #

    def eval(self, expression: str) -> float:
        """Parse and evaluate *expression*, returning a numeric result.

        Assignments ("x = 5") store the value and return it.
        """
        self._src = expression.strip()
        self._pos = 0

        result = self._parse_statement()
        self._skip_ws()
        if self._pos < len(self._src):
            raise SyntaxError(
                f"Unexpected token '{self._src[self._pos]}' at position {self._pos}"
            )
        return result

    # ------------------------------------------------------------------ #
    #  Grammar                                                             #
    #                                                                      #
    #  statement  вЖТ IDENT '=' expression  |  expression                   #
    #  expression вЖТ term  ( ('+' | '-') term  )*                          #
    #  term       вЖТ factor ( ('*' | '/') factor )*                        #
    #  factor     вЖТ '-' factor  |  '(' expression ')'  |  NUMBER | IDENT  #
    # ------------------------------------------------------------------ #

    def _parse_statement(self) -> float:
        """Handle optional variable assignment, fall back to expression."""
        # Look-ahead: if the token stream looks like "IDENT =" treat it as
        # an assignment; otherwise parse as a plain expression.
        saved_pos = self._pos
        name = self._try_read_ident()
        if name is not None:
            self._skip_ws()
            if self._pos < len(self._src) and self._src[self._pos] == "=":
                self._pos += 1          # consume '='
                self._skip_ws()
                value = self._parse_expression()
                self._vars[name] = value
                return value
        # Not an assignment вАФ restore position and parse as expression
        self._pos = saved_pos
        return self._parse_expression()

    def _parse_expression(self) -> float:
        left = self._parse_term()
        while True:
            self._skip_ws()
            if self._pos >= len(self._src):
                break
            ch = self._src[self._pos]
            if ch == "+":
                self._pos += 1
                left += self._parse_term()
            elif ch == "-":
                self._pos += 1
                left -= self._parse_term()
            else:
                break
        return left

    def _parse_term(self) -> float:
        left = self._parse_factor()
        while True:
            self._skip_ws()
            if self._pos >= len(self._src):
                break
            ch = self._src[self._pos]
            if ch == "*":
                self._pos += 1
                left *= self._parse_factor()
            elif ch == "/":
                self._pos += 1
                divisor = self._parse_factor()
                if divisor == 0:
                    raise ZeroDivisionError("Division by zero")
                left /= divisor
            else:
                break
        return left

    def _parse_factor(self) -> float:
        self._skip_ws()
        if self._pos >= len(self._src):
            raise SyntaxError("Unexpected end of expression")

        ch = self._src[self._pos]

        # Unary minus
        if ch == "-":
            self._pos += 1
            return -self._parse_factor()

        # Parenthesised sub-expression
        if ch == "(":
            self._pos += 1          # consume '('
            value = self._parse_expression()
            self._skip_ws()
            if self._pos >= len(self._src) or self._src[self._pos] != ")":
                raise SyntaxError("Expected closing ')'")
            self._pos += 1          # consume ')'
            return value

        # Number literal
        if ch.isdigit() or ch == ".":
            return self._read_number()

        # Identifier (variable)
        if ch.isalpha() or ch == "_":
            name = self._read_ident()
            if name not in self._vars:
                raise NameError(f"Undefined variable: '{name}'")
            return self._vars[name]

        raise SyntaxError(f"Unexpected character '{ch}' at position {self._pos}")

    # ------------------------------------------------------------------ #
    #  Lexer helpers                                                       #
    # ------------------------------------------------------------------ #

    def _skip_ws(self) -> None:
        while self._pos < len(self._src) and self._src[self._pos] in " \t":
            self._pos += 1

    def _read_number(self) -> float:
        start = self._pos
        dot_seen = False
        while self._pos < len(self._src):
            c = self._src[self._pos]
            if c.isdigit():
                self._pos += 1
            elif c == "." and not dot_seen:
                dot_seen = True
                self._pos += 1
            else:
                break
        token = self._src[start:self._pos]
        if not token or token == ".":
            raise SyntaxError(f"Invalid number starting at position {start}")
        return float(token)

    def _read_ident(self) -> str:
        start = self._pos
        while self._pos < len(self._src) and (
            self._src[self._pos].isalnum() or self._src[self._pos] == "_"
        ):
            self._pos += 1
        return self._src[start:self._pos]

    def _try_read_ident(self) -> str | None:
        """Return identifier string if the next non-ws token is an identifier,
        else return None without advancing pos."""
        self._skip_ws()
        if self._pos < len(self._src) and (
            self._src[self._pos].isalpha() or self._src[self._pos] == "_"
        ):
            return self._read_ident()
        return None
